class Booking:
    # Class attribute to keep track of booking count
    booking_count = 0

    def __init__(self, booking_id, passengers, flight):
        self.booking_id = booking_id
        self.passengers = passengers
        self.flight = flight
        Booking.booking_count += 1

    def confirm(self):
        print("Booking confirmed!")

    @classmethod
    def getbooking_count(cls):
        return cls.booking_count

# Do not modify the code below. This function will be called during testing.
def default_test():
    booking = Booking(booking_id=1, passengers=["Alice", "Bob"], flight="AI-202")
    booking.confirm()
    print(Booking.getbooking_count())
